var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"할아버지? 뭐하는 거야?","JPN":"おじいちゃん？　何してるの？","ENG":"Grandpa? What are you doing?","TWN":"爺爺？你在幹什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"비키게, 시그마. 이 타이탄은 부사장의 명령을 받고 왔으니.","JPN":"どいてくれ、シグマ。このタイタン、副社長の命令で来たのだ。","ENG":"Step aside, Sigma. I am here on the Vice President's order.","TWN":"讓開，西格瑪。我是奉副總的命令來的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"자네를 속인 악의 수령을 붙잡아오라는 내용일세!","JPN":"お嬢ちゃんを騙した悪の頭領を捕まえてくるようにとな！","ENG":"I am here to capture all the head of evil that you were deceived by!","TWN":"來抓住欺騙你的壞蛋BOSS！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네? 악의 수… 뭐요?","JPN":"え？　悪の……何？","ENG":"Head of what? Evil…?","TWN":"壞蛋BO……什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그것보다 무슨 소리예요? 제가 실장님과 있는 건 부사장님 명령 때문이라고요.","JPN":"それよりどういうことですか？　私が室長と一緒にいるのは、副社長の命令だからなんですよ。","ENG":"What are you talking about? The Vice President wanted me to be with Chief.","TWN":"你在說什麼啊？我和室長在一起才是副總的命令呢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"미안하군, 악당 친구. 난 그런 간악한 속임수에 넘어갈 정도로 만만한 상대가 아니라네.","JPN":"すまないな、悪党よ。吾輩はそのような奸悪な策略に乗るほど甘い相手ではない。","ENG":"I apologize, villain girl. I am not naive enough to fall for those wicked lies.","TWN":"抱歉了，壞蛋朋友。我可不是那麼容易會被三流的詭計給騙到的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"자네의 범죄이력에 대한 조사는 이미 끝마친 뒤!","JPN":"君の犯罪歴についてはすでに調査済み！","ENG":"I have already done my research on your past criminal records!","TWN":"我已經對你過往的犯罪記錄進行了調查！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"설마 그것들 전부 누명이라 할 셈인가?","JPN":"まさか、それらもすべて濡れ衣と主張するつもりか？","ENG":"Are you claiming that those were all false charges?","TWN":"難道你打算說那些全都是冤枉的嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"마냥 누명인 건 아니지만, 저도 나름 할 말은 있거든요?","JPN":"完全な濡れ衣ではないですけど、私も言いたいことはあるんですよ。","ENG":"They're not all false charges, but I should have a right to defend myself.","TWN":"雖然不全是冤枉，但我也是情有可原的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"맞습니다. 유피는 보육원 아이들을 위해 힘썼을 뿐입니다.","JPN":"そうです。ユピは孤児院の子どもたちのために頑張っただけです。","ENG":"That's right. Yuppie was only trying to feed the kids at the orphanage.","TWN":"沒錯。悠菲只是為了育幼院的孩子們在努力。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"앞뒤 사정도 모르면서 멋대로 판단하지 마시죠.","JPN":"事情も知らないで勝手に判断しないでください。","ENG":"Don't be too quick to judge her without knowing what she's been through.","TWN":"你不了解前因後果，不能隨意判斷。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"크레데레…….","JPN":"クレデレ……","ENG":"Credere...","TWN":"克蕾妲莉……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아니, 대부분은 너 때문에 벌어진 일이잖아요.","JPN":"いや、ほとんどはあなたのせいで起こったことですけど。","ENG":"Wait, but most of those charges are because of you.","TWN":"不對，那些大部分都是因為你才發生吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"하지만 그 거대한 포신. 얼추 감이 오는군요.","JPN":"でも、その巨大な砲身。だいたい予想はつきます。","ENG":"However, that massive barrel. Credere can feel it.","TWN":"但看到你那巨大的炮口，克蕾妲莉大概能猜到了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"다들 움직이지 마시죠. 아무래도 크레데레의 상대인 것 같습니다.","JPN":"みんな、動かないでください。どうやらクレデレの相手のようです。","ENG":"Stay back, everyone. This seems like Credere's match.","TWN":"大家不要動。他是克蕾妲莉的對手。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"당신 혼자서 뭘 어쩌려고 그래요?","JPN":"あなた一人でどうするつもりなんですか？","ENG":"What are you going to do alone?","TWN":"你一個人想幹什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"맞아, 크레데레. 할아버지는 엄청 강한 세기말 결전병기라구.","JPN":"そうだよ、クレデレ。おじいちゃんはめちゃくちゃ強い世紀末決戦兵器なの。","ENG":"Yeah, Credere. Grandpa is the Ultimate Doomsday Weapon.","TWN":"沒錯，克蕾妲莉。爺爺可是非常強大的世紀末決戰兵器。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"이러나저러나 저희 셋이 모여야 시그마 해적단.","JPN":"いずれにせよ私たちは三人揃ってシグマ海賊団。","ENG":"The gist is that we three are the Sigma Pirates.","TWN":"無論如何，只有我們三個人在一起才是西格瑪海盜團。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유피에 대한 모욕은 해적단 전체. 즉 크레데레를 향한 모욕입니다.","JPN":"ユピへの侮辱は海賊団全体、つまり、クレデレへの侮辱です。","ENG":"An insult toward Yuppie is an insult toward the entire crew. Which means it is an insult toward Credere.","TWN":"對悠菲的侮辱就是對西格瑪海盜團的侮辱，也就是對克蕾妲莉的侮辱。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"걱정 마시죠. 이번 싸움으로 지금까지의 실수를 만회하겠습니다.","JPN":"心配しないでください。この戦いで今までの失敗を挽回します。","ENG":"Do not fret. Credere will make up for past mistakes with this one battle.","TWN":"別擔心。這次戰鬥克蕾妲莉會彌補之前的失誤。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"크레데레…….","JPN":"クレデレ……","ENG":"Credere...","TWN":"克蕾妲莉……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"시그마 선장님. 부디 출격 명령을.","JPN":"シグマ船長。どうか出撃の命令を。","ENG":"Captain Sigma, give the orders for deployment.","TWN":"西格瑪船長，請下達出擊命令。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"좋아, 크레데레 선원! 출격을 허락한다!","JPN":"よし、クレデレ船員！　出撃を許可する！","ENG":"Great. Credere! I'll grant you your deployment!","TWN":"好，克蕾妲莉船員！允許出擊！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"시그마 해적단의 우정으로 할아버지의 오해를 푸는 거다, 얼!","JPN":"シグマ海賊団の友情により、おじいちゃんの誤解を解くのだ、ARRR！","ENG":"Resolve the Grandpa's misunderstanding with the power of the Sigma Pirates' friendship! Yarr!","TWN":"憑藉著西格瑪海盜團的友情來解開爺爺的誤會吧，唷呵！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"걱정 마시죠. 크레데레의 이름은 신뢰라는 뜻입니다.","JPN":"心配しないでください。クレデレの名前は信頼という意味ですから。","ENG":"Do not fret. Credere's name means trust.","TWN":"別擔心。克蕾妲莉的名字代表信任。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그럼…….","JPN":"それじゃあ……","ENG":"Then...","TWN":"所以……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"덤벼라, 이 범죄자들.","JPN":"かかって来い、この犯罪者ども。","ENG":"Bring it on, you criminal bastards.","TWN":"放馬過來吧，這些犯罪者！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_WHIP"},{"id":"L50_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"신뢰는 개뿔.","JPN":"なにが信頼よ。","ENG":"So trustworthy. Wow.","TWN":"信任……個鬼。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"돌아와, 크레데레-!!","JPN":"戻って来い、クレデレー！！","ENG":"Come back, Credere!","TWN":"回來呀，克蕾妲莉——!!"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};